import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

export default async function (
  request: ZuploRequest,
  context: ZuploContext,
  options: any,
  policyName: string
) {
  const tripped = await context.cache.get("cb-tripped");

  if (tripped) {
    return new Response(JSON.stringify({ error: "Circuit breaker tripped" }), {
      status: 503,
      headers: {
        "content-type": "application/json",
      },
    });
  }

  return context.next();
}

import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

export default async function (
  response: Response,
  request: ZuploRequest,
  context: ZuploContext,
  options: any,
  policyName: string
) {
  if (response.status >= 500) {
    const errorCountKey = "cb-error-count";
    let errorCount = (await context.cache.get<number>(errorCountKey)) ?? 0;
    errorCount++;

    if (errorCount >= 5) {
      await context.cache.put("cb-tripped", true, { expirationSeconds: 60 });
      await context.cache.delete(errorCountKey);
    } else {
      await context.cache.put(errorCountKey, errorCount);
    }
  } else {
    await context.cache.delete("cb-error-count");
  }

  return response;
}
